class Circle:
    def __init__(self, radius):
        self._radius = radius

    @property
    def radius(self):
        """The radius property."""
        print("Getting radius")
        return self._radius

    @radius.setter
    def radius(self, value):
        if value <= 0:
            raise ValueError("Radius must be positive")
        print(f"Setting radius to {value}")
        self._radius = value

    @radius.deleter
    def radius(self):
        print("Deleting radius")
        del self._radius

# Usage
circle = Circle(10)
print(f"The radius is: {circle.radius}")
circle.radius = 12
print(f"The new radius is: {circle.radius}")
del circle.radius

