from typing import overload, Union

@overload
def process(data: str) -> str: ...
@overload
def process(data: int) -> int: ...

def process(data: Union[str, int]) -> Union[str, int]:
    if isinstance(data, str):
        return data.upper()
    elif isinstance(data, int):
        return data * 2

# Usage
print(process("hello"))
print(process(10))

from functools import lru_cache

@lru_cache(maxsize=128)
def fibonacci(n):
    if n < 2:
        return n
    return fibonacci(n - 1) + fibonacci(n - 2)

print(fibonacci(50))
print(fibonacci.cache_info())

from functools import cache

@cache
def factorial(n):
    return n * factorial(n - 1) if n else 1

print(factorial(10))
print(factorial(5))  # uses cached intermediate results

from functools import cached_property

class DataAnalyzer:
    def __init__(self, data):
        self._data = data

    @cached_property
    def statistics(self):
        print('Computing statistics...')
        return {
            'mean': sum(self._data) / len(self._data),
            'total': sum(self._data)
        }

analyzer = DataAnalyzer([1, 2, 3, 4, 5])
print(analyzer.statistics)  # computes
print(analyzer.statistics)  # cached, no recomputation

from functools import total_ordering

@total_ordering
class Student:
    def __init__(self, name, grade):
        self.name = name
        self.grade = grade

    def __eq__(self, other):
        return self.grade == other.grade

    def __lt__(self, other):
        return self.grade < other.grade

students = [Student('Alice', 90), Student('Bob', 75), Student('Charlie', 85)]
for s in sorted(students):
    print(f'{s.name}: {s.grade}')

from functools import singledispatch

@singledispatch
def process(arg):
    print(f'Default: {arg}')

@process.register(int)
def _(arg):
    print(f'Integer: {arg * 2}')

@process.register(list)
def _(arg):
    print(f'List of {len(arg)} items')

process('hello')  # Default: hello
process(21)       # Integer: 42
process([1,2,3])  # List of 3 items

from typing import Protocol, runtime_checkable

@runtime_checkable
class Drawable(Protocol):
    def draw(self) -> None: ...

class Circle:
    def draw(self) -> None:
        print('Drawing circle')

class Square:
    def draw(self) -> None:
        print('Drawing square')

class NotDrawable:
    pass

print(isinstance(Circle(), Drawable))      # True
print(isinstance(NotDrawable(), Drawable)) # False
